import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"系统之主","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/系统之主.md","filePath":"4.资源分区/1.血统与训练/1.生理类/系统之主.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/系统之主.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"系统之主",tabindex:"-1"},[b("系统之主 "),r("a",{class:"header-anchor",href:"#系统之主","aria-label":'Permalink to "系统之主"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),n('<h1 id="系统之主-1" tabindex="-1">系统之主 <a class="header-anchor" href="#系统之主-1" aria-label="Permalink to &quot;系统之主&quot;">​</a></h1><p>系统之主</p><p>“事到如今我就不瞒你们了，我从一出生就觉醒了十多个系统，分别是呼吸系统，免疫系统，运动系统，神经系统，内分泌系统，心循环系统，淋巴系统，消化系统等等。”<br> “V我50，周四我去那白胡子老头那完成系统签到任务，他日破碎虚空带你飞升。”</p><p>D级：呼吸系统<br> 1、【在呼吸系统中，各器官都有一定的分工，鼻到各级支气管是负责传送气体，有加温、湿润和清洁空气等作用，还能在发音时产生共鸣。粘膜中有腺体，能分泌含多种免疫球蛋白（抗体）的粘液，具有抑菌、抗病毒的作用。】<br> 因此你获得了针对触及范围内的空气调节能力，能够通过鼻腔与支气管向他人传送自己呼吸的气体，略微加湿或进行清洁，亦或者是在发音时通过共鸣的把声音传达到别人喉咙里，类似腹语。<br> 这意味着你可以让触及范围内所有人都具有针对毒素的D级免疫能力，以及在范围内为自己或其他人提供全环境呼吸能力（前提是你或者附近有人能全环境呼吸）。</p><p>2、【空气由呼吸道进入肺泡，空气中的氧气从肺泡进入毛细血管的血液，经循环送遍全身，供组织细胞利用。与此同时，组织代谢产生的二氧化碳经血液循环运至肺部，通过呼吸系统排出体外。】<br> 你可以将二氧化碳运送到别人的体内，使触及范围内的所有单位立刻陷入窒息状态，不分敌我，但可以通过吸走特定目标的二氧化碳或者传输氧气来避免队友进入窒息状态，这是一个D级创伤来源的能力。</p><p>C级：免疫系统<br> 1、【免疫系统具有免疫监视、防御、调控的作用，识别和清除外来入侵。这种防止外界入侵和清除已入侵及其他有害物的功能被称之为免疫防御。使人体免于攻击。】<br> 你获得了等同传奇耐力*2点的天生防御，这是免疫系统所带来天然的防御能力，能够一定程度上免疫、排除攻击。</p><p>2、【通过自身免疫耐受和免疫调节使免疫系统内环境保持稳定，修补免疫细胞能修补受损的器官和组织，使其恢复原来的功能。】<br> 你获得快速医疗2（医疗池24），这是基于免疫细胞在修补时对受损的身体组织所带来的快速再生，可以通过输血的方式将这种快速医疗转移给别人，这要求必须血型匹配。</p><p>B级：运动系统<br> 1、【人的运动是很复杂的，包括简单的移位和高级活动如语言、书写等，都是在神经系统支配下，肌肉收缩而实现的。一些肌肉收缩，而另一些肌肉则予以协同配合，甚或有些处于拮抗地位的肌肉此时则适度放松并保持一定的紧张度。】<br> 你能够做到一些不可思议的事情，比如先是放松肌肉，但保持一定程度的发力，在极短的时间内打出堪称超.脱.力的攻击，在《刀牙》漫画之中也有所体现。</p><p>消费一个移动动作，将身体放松到极限，如同液体一样融化，却仍然保持着收缩的发力。<br> 直到下个回合开始前，你都可以在任意目标使用攻击动作时，立刻以反射动作进行等同基础速度的移动，这次移动必须解是接近发起攻击者的方向，且在移动后你可以进行一次不占用动作的标准攻击。<br> 这次攻击允许使用技艺，你也可以选择将移动与攻击结合视为一次冲锋计算。</p><p>2、【众所周知，人的躯干形成了几个体腔，保护和支持着不同脏器；肌肉也构成某些体腔壁的一部分，形成颇具弹性和韧度的保护层，当受外力冲击时，肌肉反射性地收缩，起着缓冲打击和震荡的重要作用。】<br> 仅限在发动本等级能力1的状态下，你获得DR3/穿刺。<br> 这视为全身运动系统面对攻击时反射性收缩所带来的保护，能够极大程度的缓解外在打击与震荡，但针对穿刺伤害效果不佳，且只有做出准备才有作用。</p><p>A级：心循环系统<br> 【由心脏、动脉、毛细血管和静脉等组成，是一个密闭的循环管道，血液在其中流动，维持正常的生命活动。心脏能自动并在神经系统控制下发生节律性的收缩和舒张，保证血液沿一定方向循环流动。<br> 血液主要由血细胞与血浆组成，血浆是血液的细胞外基质，而更进一步的，就是可以凭意志把身体的细胞高速磨擦，产生电流力量。作为身体细胞最有力的部分，心循环系统的核心——心脏，正是这份力量的储存之处。】<br> 在《海虎无限》中亦有接近的理论，类似鳗鱼一样的原理，却要强的多，可释放出高压电流进行攻击，而且能以闪电般的速度移动，能提取视野以外的敌人的位置、数量以及下一瞬间对手将要采取的行动。</p><p>你开启新的能量池：电磁力。<br> 你开启电磁力的全新用法：<br> 细胞重组<br> 只要能量冲不空，你的四肢将会立刻再生，哪怕头部被切下也能够连接复原，且C级提供的快速医疗也能够恢复异常点数，医疗池皆为48点，分别计算。<br> 电流强击<br> 只要能量池不空，你在进行攻击时，皆可以选择驱动电磁力进行攻击，视为同时对480米内所有敌对单位进行攻击，以强韧豁免，伤害类型改为雷电能量伤害。<br> 快如闪电<br> 只要能量池不空，你就获得机动性完美的飞行能力，且基础移动速度视为+30米，允许将攻击穿插在移动之中。</p><p>电磁力<br> 与凭【意志】把身体的细胞高速磨擦，产生的【电流力量】。这等级的力量以伏特为单位，是真正能够扭转地球磁场转动的强大能力。<br> 电磁力视为东西方通用能量，能量池的关键属性为【感知+决心】<br> 电磁力的恢复方式为：<br> 1、在进行一次长休息后自动回满。<br> 2、花费至少十五分钟吸收周围物质中蕴含的电磁力。进行一个电磁力关键属性检定，恢复成功数的电磁力。<br> 每日恢复的电磁力不能超过能量池上限的三倍。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
